@Injectable()
export class FastifyThrottlerGuard extends ThrottlerGuard {
	getRequestResponse(context: ExecutionContext): { req: any; res: any } {
		const ctx = context.switchToHttp();
		return { req: ctx.getRequest(), res: ctx.getResponse() };
	}
}
```

Note: In newer versions of @nestjs/throttler (v6+), you may only need to override `getRequestResponse`. Check the ThrottlerGuard source to see what's needed for Fastify compatibility.

