import {
	CanActivate,
	ExecutionContext,
	Injectable,
	Logger,
	UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';

import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
import { IJwtPayload, IRequestUser } from '@modules/auth/types/auth.interface';
import { SessionService } from '@modules/session/session.service';

@Injectable()
export class AuthGuard implements CanActivate {
	private readonly logger = new Logger(AuthGuard.name);

	constructor(
		private readonly jwtService: JwtService,
		private readonly sessionService: SessionService,
		private readonly reflector: Reflector,
	) {}

	async canActivate(context: ExecutionContext): Promise<boolean> {
		const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
			context.getHandler(),
			context.getClass(),
		]);
		if (isPublic) return true;

		const request = context.switchToHttp().getRequest();
		const token = this.extractTokenFromHeader(request);
		if (!token) throw new UnauthorizedException();

		let payload: IJwtPayload;
		try {
			payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
		} catch {
			throw new UnauthorizedException();
		}

		const session = await this.sessionService.getSession({
			userId: payload.user_id,
			sessionId: payload.session_id,
		});
		if (!session) throw new UnauthorizedException();

		request.user = {
			user_id: payload.user_id,
			session_id: payload.session_id,
			role: session.role,
			company_id: session.company_id,
		} satisfies IRequestUser;

		return true;
	}

	private extractTokenFromHeader(request: any): string | null {
		const [type, token] = request.headers?.authorization?.split(' ') ?? [];
		return type === 'Bearer' ? (token ?? null) : null;
	}
}

import {
	CanActivate,
	ExecutionContext,
	ForbiddenException,
	Injectable,
	Logger,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';

import { ROLES_KEY } from '@modules/auth/decorators/roles.decorator';
import { IRequestUser } from '@modules/auth/types/auth.interface';

@Injectable()
export class RolesGuard implements CanActivate {
	private readonly logger = new Logger(RolesGuard.name);

	constructor(private readonly reflector: Reflector) {}

	canActivate(context: ExecutionContext): boolean {
		const requiredRoles = this.reflector.getAllAndOverride<('admin' | 'member')[]>(ROLES_KEY, [
			context.getHandler(),
			context.getClass(),
		]);

		if (!requiredRoles || requiredRoles.length === 0) return true;

		const request = context.switchToHttp().getRequest();
		const user: IRequestUser | undefined = request.user;

		if (!user) throw new ForbiddenException();
		if (!user.role) throw new ForbiddenException();
		if (!requiredRoles.includes(user.role)) throw new ForbiddenException();

		return true;
	}
}

