	getRequestResponse(context: ExecutionContext): { req: any; res: any } {
		const ctx = context.switchToHttp();
		return { req: ctx.getRequest(), res: ctx.getResponse() };
	}
}

import { ExecutionContext, Logger, UnauthorizedException } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { Test, TestingModule } from '@nestjs/testing';

import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
import { AuthGuard } from '@modules/auth/guards/auth.guard';
import { IJwtPayload } from '@modules/auth/types/auth.interface';
import { SessionService } from '@modules/session/session.service';
import { ISession } from '@modules/session/types/session.interface';

const mockJwtService = {
	verifyAsync: jest.fn(),
};

const mockSessionService = {
	getSession: jest.fn(),
};

const mockReflector = {
	getAllAndOverride: jest.fn(),
};

const mockSession: ISession = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: 'admin',
	company_id: 'company-789',
	provider: 'github',
	ip: '127.0.0.1',
	user_agent: 'Mozilla/5.0',
	created_at: '2026-03-22T00:00:00.000Z',
	last_active: '2026-03-22T00:00:00.000Z',
};

const mockPayload: IJwtPayload = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: 'admin',
	company_id: 'company-789',
};

function createMockContext(headers: Record<string, string> = {}): ExecutionContext {
	const request = { headers, user: undefined as any };
	return {
		getHandler: jest.fn(),
		getClass: jest.fn(),
		switchToHttp: jest.fn().mockReturnValue({
			getRequest: jest.fn().mockReturnValue(request),
		}),
	} as unknown as ExecutionContext;
}

describe('AuthGuard', () => {
	let guard: AuthGuard;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				AuthGuard,
				{ provide: JwtService, useValue: mockJwtService },
				{ provide: SessionService, useValue: mockSessionService },
				{ provide: Reflector, useValue: mockReflector },
			],
		}).compile();

		guard = module.get<AuthGuard>(AuthGuard);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(guard).toBeDefined();
	});

	describe('canActivate', () => {
		it(`should return true for public routes (${IS_PUBLIC_KEY} metadata = true)`, async () => {
			mockReflector.getAllAndOverride.mockReturnValue(true);
			const context = createMockContext();

			const result = await guard.canActivate(context);

			expect(result).toBe(true);
			expect(mockJwtService.verifyAsync).not.toHaveBeenCalled();
		});

		it('should throw UnauthorizedException when Authorization header is missing', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			const context = createMockContext({});

			await expect(guard.canActivate(context)).rejects.toThrow(UnauthorizedException);
		});

		it('should throw UnauthorizedException when Authorization header has no Bearer token', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			const context = createMockContext({ authorization: 'Basic sometoken' });

			await expect(guard.canActivate(context)).rejects.toThrow(UnauthorizedException);
		});

		it('should throw UnauthorizedException when JWT verification fails', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			mockJwtService.verifyAsync.mockRejectedValue(new Error('invalid token'));
			const context = createMockContext({ authorization: 'Bearer invalid.jwt.token' });

			await expect(guard.canActivate(context)).rejects.toThrow(UnauthorizedException);
		});

		it('should throw UnauthorizedException when session is not found in Redis', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			mockJwtService.verifyAsync.mockResolvedValue(mockPayload);
			mockSessionService.getSession.mockResolvedValue(null);
			const context = createMockContext({ authorization: 'Bearer valid.jwt.token' });

			await expect(guard.canActivate(context)).rejects.toThrow(UnauthorizedException);
		});

		it('should attach IRequestUser to request and return true for valid JWT + session', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			mockJwtService.verifyAsync.mockResolvedValue(mockPayload);
			mockSessionService.getSession.mockResolvedValue(mockSession);
			const context = createMockContext({ authorization: 'Bearer valid.jwt.token' });
			const request = context.switchToHttp().getRequest();

			const result = await guard.canActivate(context);

			expect(result).toBe(true);
			expect(request.user).toEqual({
				user_id: 'user-123',
				session_id: 'session-456',
				role: 'admin',
				company_id: 'company-789',
			});
		});

		it('should call getSession with correct userId and sessionId from JWT payload', async () => {
			mockReflector.getAllAndOverride.mockReturnValue(false);
			mockJwtService.verifyAsync.mockResolvedValue(mockPayload);
			mockSessionService.getSession.mockResolvedValue(mockSession);
			const context = createMockContext({ authorization: 'Bearer valid.jwt.token' });

			await guard.canActivate(context);

			expect(mockSessionService.getSession).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
			});
		});
	});
});

import { ExecutionContext, ForbiddenException, Logger } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Test, TestingModule } from '@nestjs/testing';

import { RolesGuard } from '@modules/auth/guards/roles.guard';
import { IRequestUser } from '@modules/auth/types/auth.interface';

const mockReflector = {
	getAllAndOverride: jest.fn(),
};

function createMockContext(user?: IRequestUser): ExecutionContext {
	const request: { user?: IRequestUser } = { user };
	return {
		getHandler: jest.fn(),
		getClass: jest.fn(),
		switchToHttp: jest.fn().mockReturnValue({
			getRequest: jest.fn().mockReturnValue(request),
