	} as unknown as ExecutionContext;
}

describe('RolesGuard', () => {
	let guard: RolesGuard;

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				RolesGuard,
				{ provide: Reflector, useValue: mockReflector },
			],
		}).compile();

		guard = module.get<RolesGuard>(RolesGuard);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(guard).toBeDefined();
	});

	describe('canActivate', () => {
		it('should return true when no roles metadata is set', () => {
			mockReflector.getAllAndOverride.mockReturnValue(undefined);
			const context = createMockContext();

			const result = guard.canActivate(context);

			expect(result).toBe(true);
		});

		it('should return true when roles metadata is an empty array', () => {
			mockReflector.getAllAndOverride.mockReturnValue([]);
			const context = createMockContext();

			const result = guard.canActivate(context);

			expect(result).toBe(true);
		});

		it('should return true when user role matches required roles', () => {
			mockReflector.getAllAndOverride.mockReturnValue(['admin']);
			const user: IRequestUser = {
				user_id: 'user-123',
				session_id: 'session-456',
				role: 'admin',
				company_id: 'company-789',
			};
			const context = createMockContext(user);

			const result = guard.canActivate(context);

			expect(result).toBe(true);
		});

		it('should return true when user role is member and member is in required roles', () => {
			mockReflector.getAllAndOverride.mockReturnValue(['admin', 'member']);
			const user: IRequestUser = {
				user_id: 'user-123',
				session_id: 'session-456',
				role: 'member',
				company_id: 'company-789',
			};
			const context = createMockContext(user);

			const result = guard.canActivate(context);

			expect(result).toBe(true);
		});

		it('should throw ForbiddenException when user role is not in required roles', () => {
			mockReflector.getAllAndOverride.mockReturnValue(['admin']);
			const user: IRequestUser = {
				user_id: 'user-123',
				session_id: 'session-456',
				role: 'member',
				company_id: 'company-789',
			};
			const context = createMockContext(user);

			expect(() => guard.canActivate(context)).toThrow(ForbiddenException);
		});

		it('should throw ForbiddenException when user role is null (no company context)', () => {
			mockReflector.getAllAndOverride.mockReturnValue(['admin']);
			const user: IRequestUser = {
				user_id: 'user-123',
				session_id: 'session-456',
				role: null,
				company_id: null,
			};
			const context = createMockContext(user);

			expect(() => guard.canActivate(context)).toThrow(ForbiddenException);
		});

		it('should throw ForbiddenException when there is no user on the request', () => {
			mockReflector.getAllAndOverride.mockReturnValue(['admin']);
			const context = createMockContext(undefined);

			expect(() => guard.canActivate(context)).toThrow(ForbiddenException);
		});
	});
});

